   385→void tool_perror(
   386→	const char *func,
   387→	int err,
   388→	const char *extra,
   389→	const char *matched,
   390→	const char *info,
   391→	char **refs )
   392→{
   393→	fprintf( stderr, "%s: %s (%d)%s\n",
   394→		func, ldap_err2string( err ), err, extra ? extra : "" );
   395→
   396→	if ( matched && *matched ) {
   397→		fprintf( stderr, _("\tmatched DN: %s\n"), matched );
   398→	}
   399→
   400→	if ( info && *info ) {
   401→		fprintf( stderr, _("\tadditional info: %s\n"), info );
   402→	}
   403→
   404→	if ( refs && *refs ) {
   405→		int i;
   406→		fprintf( stderr, _("\treferrals:\n") );
   407→		for( i=0; refs[i]; i++ ) {
   408→			fprintf( stderr, "\t\t%s\n", refs[i] );
