   414→void
   415→tool_args( int argc, char **argv )
   416→{
   417→	int i;
   418→
   419→	while (( i = getopt( argc, argv, options )) != EOF ) {
   420→		int crit, ival;
   421→		char *control, *cvalue, *next;
   422→		switch( i ) {
   423→		case 'c':	/* continuous operation mode */
   424→			contoper++;
   425→			break;
   426→		case 'C':	/* referrals: obsolete */
   427→			referrals++;
   428→			break;
   429→		case 'd':
   430→			ival = strtol( optarg, &next, 10 );
   431→			if (next == NULL || next[0] != '\0') {
   432→				fprintf( stderr, "%s: unable to parse debug value \"%s\"\n", prog, optarg);
   433→				exit(EXIT_FAILURE);
   434→			}
   435→			debug |= ival;
   436→			break;
   437→		case 'D':	/* bind DN */
   438→			if( binddn != NULL ) {
   439→				fprintf( stderr, "%s: -D previously specified\n", prog );
   440→				exit( EXIT_FAILURE );
   441→			}
   442→			binddn = optarg;
   443→			break;
   444→		case 'e':	/* general extensions (controls and such) */
   445→			/* should be extended to support comma separated list of
   446→			 *	[!]key[=value] parameters, e.g.  -e !foo,bar=567
   447→			 */
   448→
   449→			crit = 0;
   450→			cvalue = NULL;
   451→			while ( optarg[0] == '!' ) {
   452→				crit++;
   453→				optarg++;
   454→			}
   455→
   456→			control = optarg;
   457→			if ( (cvalue = strchr( control, '=' )) != NULL ) {
   458→				*cvalue++ = '\0';
   459→			}
   460→
   461→			if ( strcasecmp( control, "assert" ) == 0 ) {
   462→				if( assertctl ) {
   463→					fprintf( stderr, "assert control previously specified\n");
   464→					exit( EXIT_FAILURE );
   465→				}
   466→				if( cvalue == NULL ) {
   467→					fprintf( stderr, "assert: control value expected\n" );
   468→					usage();
   469→				}
   470→
   471→				assertctl = 1 + crit;
   472→
   473→				assert( assertion == NULL );
   474→				assertion = cvalue;
   475→
   476→			} else if ( strcasecmp( control, "authzid" ) == 0 ) {
   477→				if( authzid != NULL ) {
   478→					fprintf( stderr, "authzid control previously specified\n");
   479→					exit( EXIT_FAILURE );
   480→				}
   481→#ifdef LDAP_CONTROL_OBSOLETE_PROXY_AUTHZ
   482→				if( proxydn != NULL ) {
   483→					fprintf( stderr, "authzid control incompatible with proxydn\n");
   484→					exit( EXIT_FAILURE );
   485→				}
   486→#endif /* LDAP_CONTROL_OBSOLETE_PROXY_AUTHZ */
   487→				if( cvalue == NULL ) {
   488→					fprintf( stderr, "authzid: control value expected\n" );
   489→					usage();
   490→				}
   491→				if( !crit ) {
   492→					fprintf( stderr, "authzid: must be marked critical\n" );
   493→					usage();
   494→				} else if ( crit > 1 ) {
   495→					/* purposely flag proxied authorization
   496→					 * as non-critical, to test DSA */
   497→					authzcrit = 0;
   498→				}
   499→
   500→				assert( authzid == NULL );
   501→				authzid = cvalue;
   502→
   503→#ifdef LDAP_CONTROL_OBSOLETE_PROXY_AUTHZ
   504→			} else if ( strcasecmp( control, "proxydn" ) == 0 ) {
   505→				if( proxydn != NULL ) {
   506→					fprintf( stderr, "proxydn control previously specified\n");
   507→					exit( EXIT_FAILURE );
   508→				}
   509→				if( authzid != NULL ) {
   510→					fprintf( stderr, "proxydn control incompatible with authzid\n");
   511→					exit( EXIT_FAILURE );
   512→				}
   513→				if( cvalue == NULL ) {
   514→					fprintf( stderr, "proxydn: control value expected\n" );
   515→					usage();
   516→				}
   517→				if( !crit ) {
   518→					fprintf( stderr, "proxydn: must be marked critical\n" );
   519→					usage();
   520→				} else if ( crit > 1 ) {
   521→					/* purposely flag proxied authorization
   522→					 * as non-critical, to test DSA */
   523→					authzcrit = 0;
   524→				}
   525→
   526→				assert( proxydn == NULL );
   527→				proxydn = cvalue;
   528→#endif /* LDAP_CONTROL_OBSOLETE_PROXY_AUTHZ */
   529→
